public class Main {
    public static void main(String[] args) {
        int secret = 7;
        int guess = 1;
        int attempts = 0;

        while (guess != secret) {
            System.out.println("Trying: " + guess);
            attempts++;
            guess++;
        }
        System.out.println("Found " + secret + " in " + attempts + " attempts!");
    }
}

public class Main {
    public static void main(String[] args) {
        int n = 1;

        do {
            System.out.println("n = " + n);
            n *= 2;
        } while (n < 20);

        System.out.println("Final n: " + n);
    }
}

public class Main {
    static boolean isPrime(int n) {
        if (n < 2) return false;
        for (int i = 2; i * i <= n; i++) {
            if (n % i == 0) return false;
        }
        return true;
    }

    public static void main(String[] args) {
        for (int n = 11; n <= 100; n++) {
            System.out.println("Checking: " + n);
            if (isPrime(n)) {
                System.out.println("First prime above 10: " + n);
                break;
            }
        }
    }
}

